document.addEventListener("DOMContentLoaded",function(){function getContentFromLink(clickedLink){const blogIndex=document.querySelector(".hc-blog-index--content");if(blogIndex)blogIndex.classList.add("loading");return new Promise((resolve,reject)=>{const xhr=new XMLHttpRequest();xhr.open("GET",clickedLink.href,!0);xhr.onload=function(){if(xhr.status===200){const parser=new DOMParser();const doc=parser.parseFromString(xhr.responseText,"text/html");const newContent=doc.querySelector(".hc-blog-index--content");if(newContent){const existingContent=document.querySelector(".hc-blog-index--content");if(existingContent){existingContent.innerHTML=newContent.innerHTML;window.history.replaceState(null,"",clickedLink.href);resolve("Content updated successfully")}else{reject(new Error("Existing content container not found"))}}else{reject(new Error("New content not found"))}}else{reject(new Error("Failed to load page"))}};xhr.onerror=function(){reject(new Error("Network error"))};xhr.send()}).finally(()=>{if(blogIndex)blogIndex.classList.remove("loading")})}
document.addEventListener("click",function(event){const link=event.target.closest(".pagination a, .category-list a");if(!link)return;event.preventDefault();const targetElement=document.querySelector(".hc-blog-index--content");if(targetElement){const offset=150;const elementPosition=targetElement.getBoundingClientRect().top;const offsetPosition=elementPosition+window.pageYOffset-offset;window.scrollTo({top:offsetPosition,behavior:"smooth",})}
if(link.closest(".category-list")){const listItems=document.querySelectorAll(".category-list .cat-item");listItems.forEach((li)=>li.classList.remove("current-cat"));const parentLi=link.closest(".cat-item");if(parentLi)parentLi.classList.add("current-cat")}
getContentFromLink(link).then((message)=>console.log(message)).catch((error)=>console.error(error))})})